{"name":"src/index.ts","startLine":1,"endLine":92,"content":"const returnStr = "return ";
const defaultReturn = returnStr + "0;";

function buildReadExpr(type: string) {
  return "read<" + type + ">()";
}

export function compile(source: string) {
  if (source.trim() === "") {
    return defaultReturn;
  }

  const types = ["U8", "I8", "U16", "I16", "U32", "I32", "F32", "F64"];
  const reads: string[] = [];
  const readExprs: string[] = [];

  for (const type of types) {
    const readExpr = buildReadExpr(type);
    let idx = source.indexOf(readExpr);
    while (idx !== -1) {
      reads.push(type);
      readExprs.push(readExpr);
      idx = source.indexOf(readExpr, idx + 1);
    }
  }

  if (reads.length === 0) {
    return defaultReturn;
  }

  const stdInPart = "stdIn.replace(',', ' ').split(' ')[i] || stdIn";
  const parsePrefix = "parse";
  let code = "";
  let expr = source;

  for (let i = 0; i < reads.length; i++) {
    const type: string | undefined = reads[i];
    if (type === undefined) continue;
    let parseExpr: string;
    const indexBracket = "[" + i + "]";
    if (type === "F32" || type === "F64") {
      parseExpr = (parsePrefix + "Float(" + stdInPart + ")").replace(
        "[i]",
        indexBracket,
      );
    } else {
      parseExpr = (parsePrefix + "Int(" + stdInPart + ", 10)").replace(
        "[i]",
        indexBracket,
      );
    }
    code += "const v" + i + " = " + parseExpr + ";\n";
    const readExpr: string | undefined = readExprs[i];
    if (readExpr === undefined) continue;
    expr = expr.replace(readExpr, "v" + i);
  }

  // Split by semicolons and process each statement
  const statements = splitStatements(expr);
  for (const stmt of statements) {
    code += convertStatement(stmt.trim()) + "\n";
  }

  return code;
}

function splitStatements(s: string): string[] {
  const parts: string[] = [];
  let current = "";
  for (let i = 0; i < s.length; i++) {
    if (s[i] === ";") {
      parts.push(current);
      current = "";
    } else {
      current += s[i];
    }
  }
  if (current.length > 0) {
    parts.push(current);
  }
  return parts;
}

function convertStatement(stmt: string): string {
  // Check for "let x : Type = value" pattern
  const letIdx = stmt.indexOf("let ");
  if (letIdx === -1) {
    // Not a declaration, treat as expression to return
    return returnStr + stmt;
  }

  // Extract variable name and skip type annotation
  let i = letIdx + "let ".length;
  const varNameStart = i;
  while (i < stmt.length && stmt[i] !== ":" && stmt[i] !== "=") {
    i++;
  }
  const varName = stmt.substring(varNameStart, i).trim();

  // Skip past type annotation if present
  if (stmt[i] === ":") {
    while (i < stmt.length && stmt[i] !== "=") {
      i++;
    }
  }

  // Find the value part after '='
  if (i < stmt.length && stmt[i] === "=") {
    const value = stmt.substring(i + 1).trim();
    return "const " + varName + " = " + value;
  }

  return "";
}
"}

